changeSet.sql:
ALTER TABLE character_class_levels DROP CONSTRAINT IF EXISTS fk_ccl_class_content;
ALTER TABLE character_class_levels
    ADD CONSTRAINT fk_ccl_class_content
    FOREIGN KEY (class_id) REFERENCES character_class(class_id);

ALTER TABLE character_skill_proficiencies DROP CONSTRAINT IF EXISTS fk_csp_skill_content;
ALTER TABLE character_skill_proficiencies
    ADD CONSTRAINT fk_csp_skill_content
    FOREIGN KEY (skill_id) REFERENCES skill(skill_id);

ALTER TABLE character_stats DROP CONSTRAINT IF EXISTS fk_cstat_ability_content;
ALTER TABLE character_stats
    ADD CONSTRAINT fk_cstat_ability_content
    FOREIGN KEY (stat_type_id) REFERENCES ability_score(ability_score_id);

ALTER TABLE character_wallets DROP CONSTRAINT IF EXISTS fk_wallet_currency_content;
ALTER TABLE character_wallets
    ADD CONSTRAINT fk_wallet_currency_content
    FOREIGN KEY (currency_type_id) REFERENCES currency(currency_id);

ALTER TABLE wallet_transactions DROP CONSTRAINT IF EXISTS fk_wallet_tx_currency_content;
ALTER TABLE wallet_transactions
    ADD CONSTRAINT fk_wallet_tx_currency_content
    FOREIGN KEY (currency_type_id) REFERENCES currency(currency_id);

ALTER TABLE character_known_spells DROP CONSTRAINT IF EXISTS fk_cks_spell_content;
ALTER TABLE character_known_spells
    ADD CONSTRAINT fk_cks_spell_content
    FOREIGN KEY (spell_id) REFERENCES spell(spell_id);

ALTER TABLE characters DROP CONSTRAINT IF EXISTS fk_char_background_content;
ALTER TABLE characters
    ADD CONSTRAINT fk_char_background_content
    FOREIGN KEY (background_id) REFERENCES background(background_id);

rollback.sql:
ALTER TABLE character_class_levels DROP CONSTRAINT IF EXISTS fk_ccl_class_content;
ALTER TABLE character_skill_proficiencies DROP CONSTRAINT IF EXISTS fk_csp_skill_content;
ALTER TABLE character_stats DROP CONSTRAINT IF EXISTS fk_cstat_ability_content;
ALTER TABLE character_wallets DROP CONSTRAINT IF EXISTS fk_wallet_currency_content;
ALTER TABLE wallet_transactions DROP CONSTRAINT IF EXISTS fk_wallet_tx_currency_content;
ALTER TABLE character_known_spells DROP CONSTRAINT IF EXISTS fk_cks_spell_content;
ALTER TABLE characters DROP CONSTRAINT IF EXISTS fk_char_background_content;
